  const fam = player.chosenFamily;
  const alliedZones = fam ? (RIVAL_FAMILIES[fam]?.turfZones || []) : [];

  const playerAtkPower = typeof calculateTurfAttackPower === 'function' ? calculateTurfAttackPower() : (player.turf.power || 100);
