// -- Admin Tutorial Management --
function adminResetTutorials(action) {
  if (action === 'contextual') {
    reEnableContextualTutorials();
    showAdminPanel();
  } else if (action === 'narrative') {
    startNarrativeGuide();
  } else if (action === 'welcome') {
    // Clear mode so the welcome popup triggers
    localStorage.removeItem('tutorialMode');
    localStorage.removeItem('tutorialSkipAll');
    Object.keys(TUTORIAL_CONTENT).forEach(id => {
      localStorage.removeItem('tutorialSeen_' + id);
    });
    localStorage.removeItem('narrativeComplete');
    showTutorialWelcome();
  } else if (action === 'clear') {
    localStorage.removeItem('tutorialMode');
    localStorage.removeItem('tutorialSkipAll');
    localStorage.removeItem('narrativeComplete');
    Object.keys(TUTORIAL_CONTENT).forEach(id => {
      localStorage.removeItem('tutorialSeen_' + id);
    });
    showBriefNotification('Admin: All tutorial data cleared.', 'success');
    logAction('[Admin] Tutorial data cleared');
    showAdminPanel();
  }
}
window.adminResetTutorials = adminResetTutorials;

// -- Admin Kill Player ---
function buildAdminKillPlayerList() {
  const isOnline = typeof onlineWorldState !== 'undefined' && onlineWorldState.isConnected;
  if (!isOnline) {
    return '<div style="color: #8a7a5a; font-style: italic; text-align: center;">Not connected to online world.</div>';
  }
  const players = Object.values(onlineWorldState.playerStates || {});
  if (players.length === 0) {
    return '<div style="color: #8a7a5a; font-style: italic; text-align: center;">No players online.</div>';
  }
  // Local escapeHTML in case multiplayer.js version isn't in scope
  const esc = (s) => String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
  let html = '';
  players.forEach(p => {
    const isMe = p.playerId === onlineWorldState.playerId;
    const safeName = esc(p.name);
    const safeId = esc(p.playerId);
    html += `
      <div style="display:flex; justify-content:space-between; align-items:center; padding:8px; margin:4px 0; background:rgba(20,18,10,0.3); border-radius:4px; border-left:3px solid ${isMe ? '#c0a062' : '#8b3a3a'};">
        <div>
          <strong style="color:${isMe ? '#c0a062' : '#f5e6c8'};">${safeName}${isMe ? ' (You)' : ''}</strong>
          <br><small style="color:#8a7a5a;">Level ${p.level || 1} &bull; ${p.reputation || 0} respect</small>
        </div>
        ${isMe ? '' : `<button onclick="adminKillPlayer('${safeId}', '${safeName}')" style="background:#4a0e0e; color:#ff6b6b; border:1px solid #8b3a3a; padding:6px 12px; border-radius:4px; cursor:pointer; font-weight:bold;">&#9760; Kill</button>`}
      </div>
    `;
  });
  return html;
}

function adminRefreshPlayerList() {
  const container = document.getElementById('admin-kill-player-list');
  if (container) {
    container.innerHTML = buildAdminKillPlayerList();
  }
  showBriefNotification('Player list refreshed', 'success');
}

async function adminKillPlayer(targetPlayerId, targetName) {
  if (window.ui && window.ui.confirm) {
    const result = await window.ui.confirm(`Execute ${targetName}? This will trigger permadeath for their character.`, 'Confirm Kill');
    if (result === true) {
      executeAdminKill(targetPlayerId, targetName);
    }
  } else {
    if (confirm(`Execute ${targetName}? This will trigger permadeath for their character.`)) {
      executeAdminKill(targetPlayerId, targetName);
    }
  }
}

function executeAdminKill(targetPlayerId, targetName) {
  const authState = getAuthState();
  if (!authState.isAdmin || !authState.token) {
    showBriefNotification('Admin: Not authorized!', 'error');
    return;
  }
  const isOnline = typeof onlineWorldState !== 'undefined' && onlineWorldState.isConnected && onlineWorldState.socket;
  if (!isOnline) {
    showBriefNotification('Admin: Not connected to server!', 'error');
    return;
  }
  // Send admin kill command to the server with auth token for verification
  onlineWorldState.socket.send(JSON.stringify({
    type: 'admin_kill_player',
    targetPlayerId: targetPlayerId,
    authToken: authState.token,
    causeOfDeath: `Executed by order of the Don`
  }));
  showBriefNotification(`Admin: Kill order sent for ${targetName}`, 'warning');
  logAction(`[Admin] Sent kill order for ${targetName}`);
}

// Function to refresh the currently active screen
// IMPORTANT: This runs periodically via the screen refresh timer.
// Never do a full innerHTML rebuild here -- only patch individual elements
// to avoid destroying hover/focus states and causing visible flicker.
function refreshCurrentScreen() {
  // Check if jobs screen is visible -- patch buttons only
  const jobsScreen = document.getElementById("jobs-screen");
  if (jobsScreen && jobsScreen.style.display !== "none") {
    refreshJobsButtons();
    return;
  }

  // If store is open, only refresh dynamic elements to avoid flicker
  const storeScreen = document.getElementById("store-screen");
  if (storeScreen && storeScreen.style.display !== "none") {
    if (typeof refreshStoreDynamicElements === 'function') {
      refreshStoreDynamicElements();
    }
    return;
  }

  // Skills -- no per-second refresh needed (points update in HUD bar)
  // Business -- no per-second refresh needed

  // Gang screen -- refresh timer countdowns for operations and training
  const gangScreen = document.getElementById("gang-screen");
  if (gangScreen && gangScreen.style.display !== "none") {
    refreshGangTimers();
    return;
  }
}

// Lightweight per-second gang timer refresh -- re-renders the gang screen
// only when operations or training are active to keep countdowns live.
// Throttled to every 5 seconds to avoid scroll/interaction disruption.
let _lastGangTimerRefresh = 0;
function refreshGangTimers() {
  const hasActiveTimers =
    (player.gang.activeOperations && player.gang.activeOperations.length > 0) ||
    (player.gang.trainingQueue && player.gang.trainingQueue.length > 0);
  if (!hasActiveTimers) return;

  const now = Date.now();
  if (now - _lastGangTimerRefresh < 5000) return;
  _lastGangTimerRefresh = now;

  // Only re-render if the main gang content is showing (not crew details sub-screen)
  const gangContent = document.getElementById("gang-content");
  if (!gangContent) return;
  // Refresh the gang screen preserving the currently active tab
  showGang(_currentGangTab);
}

// Lightweight per-second refresh: only patch job button text / color / disabled
// without replacing any DOM nodes. This prevents hover-state flicker.
function refreshJobsButtons() {
  const jobListElement = document.getElementById("job-list");
  if (!jobListElement) return;

  const buttons = jobListElement.querySelectorAll('button[data-job-index]');
  buttons.forEach(btn => {
    const index = parseInt(btn.getAttribute('data-job-index'), 10);
    const job = jobs[index];
    if (!job) return;

    const hasRequirements = hasRequiredItems(job.requiredItems);
    const cooldownLeft = getJobCooldownRemaining(index);

    let buttonColor = "green";
    let buttonText = "Work";
    let isDisabled = false;

    if (!hasRequirements) {
      buttonColor = "red";
      buttonText = "Requirements Not Met";
      isDisabled = true;
    } else if (cooldownLeft > 0) {
      buttonColor = "orange";
      buttonText = `Cooldown: ${formatCooldownTime(cooldownLeft)}`;
      isDisabled = true;
    } else if (job.risk === "legendary") {
      buttonColor = "#8b6a4a";
      buttonText = "Legendary Hit";
    } else if (job.risk === "extreme") {
      buttonColor = "#7a2a2a";
      buttonText = "Go All In";
    } else if (job.risk === "very high") {
      buttonColor = "#e67e22";
      buttonText = "High Stakes";
    } else if (job.risk === "high") {
      buttonColor = "gold";
      buttonText = "Execute";
    }

    // Only touch the DOM if something actually changed
    if (btn.style.backgroundColor !== buttonColor) btn.style.backgroundColor = buttonColor;
    if (btn.disabled !== isDisabled) btn.disabled = isDisabled;
    if (btn.textContent.trim() !== buttonText) btn.textContent = buttonText;
  });
}

// Calculate heat-adjusted jail chance for display purposes (approximation including heat + stealth)
function getDisplayJailChance(baseJailChance) {
  const heatLevel = player.heat || 0;
  // Apply stealth reduction
  let stealthBonus = (player.skillTree?.stealth?.shadow_step || 0) * 2;
  stealthBonus += (player.skillTree?.stealth?.escape_artist || 0) * 3;
  stealthBonus += (player.skillTree?.stealth?.infiltration || 0) * 2;
  let adjusted = Math.max(1, baseJailChance - stealthBonus);

  // Apply heat modifier (must match doJob logic)
  if (heatLevel <= 10) {
    adjusted = Math.floor(adjusted * 0.60);
  } else if (heatLevel <= 25) {
    adjusted = Math.floor(adjusted * 0.80);
  } else if (heatLevel <= 50) {
    // Normal police attention -- no modifier
  } else if (heatLevel <= 75) {
    adjusted = Math.floor(adjusted * 1.30) + 5;
  } else {
    adjusted = Math.floor(adjusted * 1.60) + 15;
  }
  return Math.max(1, Math.min(95, adjusted));
}

// Full job-list rebuild -- called by showJobs() and cooldown timer tick.
function refreshJobsList() {
  const jobListElement = document.getElementById("job-list");
  if (!jobListElement) {
    showJobs();
    return;
  }

  if (player.inJail) {
    jobListElement.innerHTML = '<p style="color: #8b3a3a; text-align: center; padding: 20px;">You cannot work while in jail!</p>';
    return;
  }

  let jobListHTML = jobs.map((job, index) => {
    const hasItems = hasRequiredItems(job.requiredItems);
    const hasRequirements = hasItems;
    const cooldownLeft = getJobCooldownRemaining(index);
    const cooldownTotal = getJobCooldown(job);

    let payoutText = "";
    if (job.special === "car_theft") {
      payoutText = "Steal random car to sell";
    } else if (job.paysDirty) {
      payoutText = `<span style="color:#8b3a3a;">$${job.payout[0].toLocaleString()} to $${job.payout[1].toLocaleString()} (DIRTY MONEY)</span>`;
    } else {
      payoutText = `$${job.payout[0].toLocaleString()} to $${job.payout[1].toLocaleString()}`;
    }

    let buttonColor = "green";
    let buttonText = "Work";
    let isDisabled = false;

    if (!hasRequirements) {
      buttonColor = "red";
      buttonText = "Requirements Not Met";
      isDisabled = true;
    } else if (cooldownLeft > 0) {
      buttonColor = "orange";
      buttonText = `Cooldown: ${formatCooldownTime(cooldownLeft)}`;
      isDisabled = true;
    } else if (job.risk === "legendary") {
      buttonColor = "#8b6a4a";
      buttonText = "Legendary Hit";
    } else if (job.risk === "extreme") {
      buttonColor = "#7a2a2a";
      buttonText = "Go All In";
    } else if (job.risk === "very high") {
      buttonColor = "#e67e22";
      buttonText = "High Stakes";
    } else if (job.risk === "high") {
      buttonColor = "gold";
      buttonText = "Execute";
    }

    // Build inline details visible without hover
    let detailParts = [];
    if (job.requiredItems.length > 0) {
      const itemParts = job.requiredItems.map(item => {
        const hasIt = player.inventory && player.inventory.some(inv => inv.name === item);
        const color = hasIt ? '#8a9a6a' : '#ff6b6b';
        const icon = hasIt ? '\u2713' : '\u2717';
        return `<span style="color:${color};">${icon} ${item}</span>`;
      });
      detailParts.push(...itemParts);
    }
    let detailsHTML = '';
    if (detailParts.length > 0) {
      detailsHTML += `<br><small style="line-height:1.6;">${detailParts.join(' &nbsp; ')}</small>`;
    }
    detailsHTML += `<br><small style="color:#8a7a5a;">Jail: ${getDisplayJailChance(job.jailChance)}% | Damage: ${job.healthLoss} | Heat: +${job.heatGain} | Respect: <span style="color:#c0a062;">${JOB_REP_BY_RISK[job.risk] || 0.5}</span></small>`;

    // Cooldown display
    const cooldownDisplay = cooldownLeft > 0
      ? `<span style="color:#e67e22;">Cooldown: ${formatCooldownTime(cooldownLeft)}</span>`
      : `<span style="color:#8a9a6a;">Ready</span>`;

    return `
      <li>
        <strong>${job.name}</strong> - ${payoutText}
        <br><small>Risk: ${job.risk.toUpperCase()} | ${cooldownDisplay} | Base: ${formatCooldownTime(cooldownTotal)}</small>
        ${detailsHTML}
        <button data-job-index="${index}" style="background-color: ${buttonColor};"
            onclick="startJob(${index})"
            ${isDisabled ? 'disabled' : ''}>
          ${buttonText}
        </button>
      </li>
    `;
  }).join('');

  jobListElement.innerHTML = jobListHTML;
}

